IslandLevelConfig = {}
IslandLevelConfig.level = {}

function IslandLevelConfig:init(config)
    for i, v in pairs(config) do
        local item = {}
        item.id = tonumber(v.id)
        item.level = tonumber(v.level)
        item.min_exp = tonumber(v.min_exp)
        item.max_exp = tonumber(v.max_exp)
        self.level[i] = item
    end
end

function IslandLevelConfig:getLevelByExp(exp)
    for i, k in pairs(self.level) do
        if k.min_exp <= exp and k.max_exp >= exp then
            return k.level
        end
    end
    return
end

function IslandLevelConfig:getMaxExp(exp_lv)
    for _, exp in pairs(self.level) do
        if tonumber(exp.level) == tonumber(exp_lv) then
            if tostring(exp.max_exp) == "###" then
                return 10000, true
            else
                return tonumber(exp.max_exp), false
            end
        end
    end
    return 10000, true
end




return IslandLevelConfig